# @cctt_verify {"v":2,"sym":"sympy.physics.quantum.tests.test_boson.test_boson_states","kind":"function","src_hash":"307f8453357787c9","in":{"base":"Any"},"out":{"base":"Any","pred":"(BosonFockBra(0) * BosonFockKet(1)).doit() == 0 and (BosonFockBra(1) * BosonFockKet(1)).doit() == 1 and (BosonCoherentBra(alpha1) * BosonCoherentKet(alpha1)).doit() == 1 and (BosonCoherentBra(alpha2) * BosonCoherentKet(alpha2)).doit() == 1 and qapply(a * BosonCoherentKet(alpha1)) == alpha1 * BosonCoherentKet(alpha1)"},"spec":{"lhs":"test_boson_states()","rhs":"test_boson_states produces the expected output","over":{"base":"Any"},"name":"test_boson_states_correct"},"guarantee":"test_boson_states produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.physics.quantum.tests.test_boson.test_boson_states_correct","statement":"Path(test_boson_states(x), test_boson_states produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"a3a07b0b8981475d"}
def test_boson_states():
    a = BosonOp("a")

    # Fock states
    n = 3
    assert (BosonFockBra(0) * BosonFockKet(1)).doit() == 0
    assert (BosonFockBra(1) * BosonFockKet(1)).doit() == 1
    assert qapply(BosonFockBra(n) * Dagger(a)**n * BosonFockKet(0)) \
        == sqrt(prod(range(1, n+1)))

    # Coherent states
    alpha1, alpha2 = 1.2, 4.3
    assert (BosonCoherentBra(alpha1) * BosonCoherentKet(alpha1)).doit() == 1
    assert (BosonCoherentBra(alpha2) * BosonCoherentKet(alpha2)).doit() == 1
    assert abs((BosonCoherentBra(alpha1) * BosonCoherentKet(alpha2)).doit() -
               exp((alpha1 - alpha2) ** 2 * Rational(-1, 2))) < 1e-12
    assert qapply(a * BosonCoherentKet(alpha1)) == \
        alpha1 * BosonCoherentKet(alpha1)
